mapper.select:
select sco.order_no,sco.recharge_amount,sco.gift_amount,sco.pay_type,sco.pay_channel,sco.pay_time,sco.out_trade_no, sco.uid,u.nickname,u.avatar,u.phone from eb_shopping_credits_order sco left join eb_user as u on sco.uid = u.id where sco.paid = 1
and sco.mer_id = #{merId}
and sco.order_no like CONCAT('%',#{orderNo},'%')
and sco.pay_type = #{payType}
and sco.pay_time between #{startTime} and #{endTime}
and ( sco.uid like CONCAT('%',#{keywords},'%') or u.nickname like CONCAT('%',#{keywords},'%') or u.phone like CONCAT('%',#{keywords},'%') )
and sco.uid = #{uid}
and u.nickname like CONCAT('%',#{nickname},'%')
and u.phone like CONCAT('%',#{phone},'%')
order by sco.id desc
